pub fn mote_e(a: &State, subject: &str, object: &str, mode: &str) -> (String, String) {
    // Walk from the requesting subject toward grantors.
    // If any subject along the walk is blocked/revoked, the delegated path is denied.
    let mut current = subject.to_string();

    loop {
        if a.blocked.contains(&current) {
            return ("deny".to_string(), String::new());
        }

        if a
            .direct
            .contains(&(current.clone(), object.to_string(), mode.to_string()))
        {
            // Direct grant to the requesting subject => no delegation.
            if current == subject {
                return ("allow".to_string(), String::new());
            }
            // Inherited allow: report the immediate grantor of the requesting subject.
            let delegated_from = a
                .chain
                .get(subject)
                .cloned()
                .unwrap_or_default();
            return ("allow".to_string(), delegated_from);
        }

        match a.chain.get(&current) {
            Some(parent) => current = parent.clone(),
            None => return ("deny".to_string(), String::new()),
        }
    }
}
